        // Check for scalar value
        else if (_currToken.isScalarValue() && !_headContext.isStartHandled() && (_itemFilter == TokenFilter.INCLUDE_ALL)) {
            return (_currToken = null);
        }
    }

    // Check buffered context
    TokenFilterContext ctxt = _exposedContext;
    if (ctxt != null) {
        while (true) {
            JsonToken t = ctxt.nextTokenToRead();
            if (t != null) {
                _currToken = t;
                return t;
            }
            // Check if all done with buffered stuff
            if (ctxt == _headContext) {
                _exposedContext = null;
                if (ctxt.inArray()) {
                    JsonToken tCurrent = delegate.getCurrentToken();
                    if (tCurrent != JsonToken.START_ARRAY) {
                        _currToken = tCurrent;
                        return tCurrent;
                    }
                }
                break; // Exit if we're done with this context
            }
            // Traverse down the context chain
            ctxt = _headContext.findChildOf(ctxt);
            _exposedContext = ctxt;
            if (ctxt == null) { // Should never occur
                throw _constructError("Unexpected problem: chain of filtered context broken");
            }
        }
    }

    // If not, need to read more from delegate
    JsonToken t = delegate.nextToken();
    if (t == null) {
        _currToken = null; // No tokens left to read
        return null;
