        case ID_START_OBJECT:
            handleStartToken(t, filter);
            break;
        case ID_END_ARRAY:
        case ID_END_OBJECT:
            handleEndToken(t);
            break;
        case ID_FIELD_NAME:
            handleFieldName(t);
            break;
        default: // Scalar value
            handleScalarValue(t, filter);
            break;
    }

    // If token was not yet found, offlined handling
    return _nextToken2();
}

private void handleStartToken(JsonToken t, TokenFilter filter) throws IOException {
    if (filter == TokenFilter.INCLUDE_ALL) {
        _headContext = _headContext.createChildContext(t);
        _currToken = t;
        return;
    }
    if (filter != null) {
        filter = _headContext.checkValue(filter);
        if (filter != null) {
            _itemFilter = filter;
            _headContext = _headContext.createChildContext(t);
            _currToken = t;
            return;
        }
    }
    delegate.skipChildren(); // If not included, skip children
}

private void handleEndToken(JsonToken t) {
    boolean returnEnd = _headContext.isStartHandled();
    _headContext = _headContext.getParent();
    _itemFilter = _headContext.getFilter();
    if (returnEnd) {
        _currToken = t;
    }
}

private void handleFieldName(JsonToken t) throws IOException {
    String name = delegate.getCurrentName();
    TokenFilter filter = _headContext.setFieldName(name);
    if (filter == TokenFilter.INCLUDE_ALL) {
        _itemFilter = filter;
        if (!_includePath && _includeImmediateParent && !_headContext.isStartHandled()) {
            _headContext.nextTokenToRead(); // This handles surrounding context
        }
        _currToken = t;
        return;
    }
    if (filter == null) {
        delegate.nextToken();
        delegate.skipChildren();
        return;
    }
    filter = filter.includeProperty(name);
    if (filter != null) {
        _itemFilter = filter;
        if (filter == TokenFilter.INCLUDE_ALL) {
            if (_includePath) {
                _currToken = t;
            }
        } else if (_includePath) {
            JsonToken bufferedToken = _nextTokenWithBuffering(_headContext);
            if (bufferedToken != null) {
                _currToken = bufferedToken;
            }
        }
    } else {
        delegate.nextToken();
        delegate.skipChildren();
    }
}

private void handleScalarValue(JsonToken t, TokenFilter filter) {
    if (filter == TokenFilter.INCLUDE_ALL) {
        _currToken = t;
        return;
    }
    if (filter != null) {
        filter = _headContext.checkValue(filter);
        if (filter == TokenFilter.INCLUDE_ALL || (filter != null && filter.includeValue(delegate))) {
            _currToken = t;
