```java
public JsonToken nextToken() throws IOException
{
    // Check if we're allowing multiple matches and there are conditions on the current token
    if (!_allowMultipleMatches && (_currToken != null) && (_exposedContext == null)) {
        // If the current token is the end of a structure and the head context is handled, return null
        if (_currToken.isStructEnd()) {
            if (_headContext.isStartHandled()) {
                return (_currToken = null);
            }
        } else if (_currToken.isScalarValue()) {
            // If the head context is not handled and we're including all, return null
            if (!_headContext.isStartHandled() && (_itemFilter == TokenFilter.INCLUDE_ALL)) {
                return (_currToken = null);
            }
        }
    }

    // Check for buffered context
    TokenFilterContext ctxt = _exposedContext;

    if (ctxt != null) {
        // Process the buffered context for tokens
        while (true) {
            JsonToken t = ctxt.nextTokenToRead();
            if (t != null) {
                _currToken = t;
                return t;
            }
            // Finished with the buffered context?
            if (ctxt == _headContext) {
                _exposedContext = null;
                if (ctxt.inArray()) {
                    t = delegate.getCurrentToken();
                    if (t != JsonToken.START_ARRAY) {
                        _currToken = t;
                        return t;
                    }
                }
                break;
            }
            // Move up the context chain
            ctxt = _headContext.findChildOf(ctxt);
            _exposedContext = ctxt;
            if (ctxt == null) {
                throw _constructError("Unexpected problem: chain of filtered context broken");
            }
        }
    }

    // Need to read more tokens
    JsonToken t = delegate.nextToken();
    if (t == null) {
        // No tokens left; return null
        _currToken = t;
        return t;
    }

    // Determine filtering and context creation based on the token type
    TokenFilter f;

    switch (t.id()) {
        case ID_START_ARRAY:
        case ID_START_OBJECT:
            f = _itemFilter;
            if (f == TokenFilter.INCLUDE_ALL) {
                _headContext = (t.id() == ID_START_ARRAY) ? 
                    _headContext.createChildArrayContext(f, true) : 
                    _headContext.createChildObjectContext(f, true);
                return (_currToken = t);
            } 
            if (f == null) {
                delegate.skipChildren();
                break;
            }
            f = _headContext.checkValue(f);
            if (f == null) {
                delegate.skipChildren();
                break;
            }
            if (f != TokenFilter.INCLUDE_ALL) {
                f = (t.id() == ID_START_ARRAY) ? f.filterStartArray() : f.filterStartObject();
            }
            _itemFilter = f;
            _headContext = (t.id() == ID_START_ARRAY) ? 
                _headContext.createChildArrayContext(f, false) : 
                _headContext.createChildObjectContext(f, false);
            // Buffering check
            if (_includePath) {
                t = _nextTokenWithBuffering(_headContext);
                if (t != null) {
                    _currToken = t;
                    return t;
                }
            }
            break;

        case ID_END_ARRAY:
        case ID_END_OBJECT:
            boolean returnEnd = _headContext.isStartHandled();
            f = _headContext.getFilter();
            if (f != null && f != TokenFilter.INCLUDE_ALL) {
                if (t.id() == ID_END_ARRAY) {
                    f.filterFinishArray();
                } else {
                    f.filterFinishObject();
                }
            }
            _headContext = _headContext.getParent();
            _itemFilter = _headContext.getFilter();
            if (returnEnd) {
                return (_currToken = t);
            }
            break;

        case ID_FIELD_NAME:
            final String name = delegate.getCurrentName();
            f = _headContext.setFieldName(name);
            if (f == TokenFilter.INCLUDE_ALL) {
                _itemFilter = f;
                if (!_includePath) {
                    if (_includeImmediateParent && !_headContext.isStartHandled()) {
                        t = _headContext.nextTokenToRead();
                        _exposedContext = _headContext;
                    }
                }
                return (_currToken = t);
            }
            if (f == null) {
                delegate.nextToken();
                delegate.skipChildren();
                break;
            }
            f = f.includeProperty(name);
            if (f == null) {
                delegate.nextToken();
                delegate.skipChildren();
                break;
            }
            _itemFilter = f;
            if (f == TokenFilter.INCLUDE_ALL) {
                if (_includePath) {
                    return (_currToken = t);
                }
            }
            if (_includePath) {
                t = _nextTokenWithBuffering(_headContext);
                if (t != null) {
                    _currToken = t;
                    return t;
                }
            }
            break;

        default: // Handle scalar values
            f = _itemFilter;
            if (f == TokenFilter.INCLUDE_ALL) {
                return (_currToken = t);
            }
            if (f != null) {
                f = _headContext.checkValue(f);
                if (f == TokenFilter.INCLUDE_ALL || (f != null && f.includeValue(delegate))) {
                    return (_currToken = t);
                }
            }
            break;
    }

    // If token was not found, handle it
    return _nextToken2();
}
